CREATE TABLE customers (
	id int auto_increment,
    customerKey int,
    geographyKey int,
    name varchar(100),
    birthDate date,
    maritalStatus varchar(1),
    gender varchar(1),
    yearlyIncome decimal(12,2),
    numberOfChildrenAtHome int,
    occupation varchar(100),
    houseOwnerFlag int,
    numberOfCarsOwned int,
    addressLine1 varchar(150),
    addressLine2 varchar(100),
    phone varchar(50),
    dateFirstPurchased date,
    PRIMARY KEY(id)
);

